#!/usr/bin/env python3
"""Добавление Главы 1 в пояснительную записку."""

from docx import Document
from docx.shared import Pt, Cm
from docx.enum.text import WD_ALIGN_PARAGRAPH
import os

path = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'Пояснительная_записка.docx')
doc = Document(path)

def add_heading_c(text, size=16):
    p = doc.add_paragraph()
    p.alignment = WD_ALIGN_PARAGRAPH.CENTER
    run = p.add_run(text)
    run.font.name = 'Times New Roman'
    run.font.size = Pt(size)
    run.bold = True
    p.paragraph_format.space_before = Pt(12)
    p.paragraph_format.space_after = Pt(6)

def add_heading_l(text, size=14):
    p = doc.add_paragraph()
    p.alignment = WD_ALIGN_PARAGRAPH.LEFT
    run = p.add_run(text)
    run.font.name = 'Times New Roman'
    run.font.size = Pt(size)
    run.bold = True
    p.paragraph_format.space_before = Pt(12)
    p.paragraph_format.space_after = Pt(6)

def add_para(text):
    p = doc.add_paragraph()
    p.alignment = WD_ALIGN_PARAGRAPH.JUSTIFY
    p.paragraph_format.first_line_indent = Cm(1.25)
    p.paragraph_format.line_spacing = 1.5
    p.paragraph_format.space_after = Pt(0)
    p.paragraph_format.space_before = Pt(0)
    run = p.add_run(text)
    run.font.name = 'Times New Roman'
    run.font.size = Pt(14)

doc.add_page_break()

# ==================== ГЛАВА 1 ====================
add_heading_c('1. АНАЛИТИЧЕСКИЙ ОБЗОР СУЩЕСТВУЮЩИХ ПОДХОДОВ\nК АУТЕНТИФИКАЦИИ И УПРАВЛЕНИЮ ПРАВАМИ ДОСТУПА\nНА ОСНОВЕ РАСПОЗНАВАНИЯ ЛИЦ')

# ---- 1.1 ----
add_heading_l('1.1 Анализ тенденций информационной безопасности и методов аутентификации')

add_para('Информационная безопасность корпоративных систем является одной из ключевых проблем современного предприятия. С ростом цифровизации строительной отрасли увеличивается объём данных, обрабатываемых в информационных системах: проектная документация, строительные чертежи, сметная документация, финансовые отчёты, персональные данные сотрудников и подрядчиков.')

add_para('Согласно статистике ФСТЭК России, количество инцидентов информационной безопасности в секторе строительства и инфраструктуры возросло на 37% за период 2022–2024 годов. Основными векторами атак являются фишинг, компрометация учётных данных и атаки на веб-приложения.')

add_para('Аутентификация пользователей является первым рубежом защиты информационной системы. В теории информационной безопасности выделяют три основных фактора аутентификации:')

add_para('1) Фактор знания (что-то, что пользователь знает): пароли, PIN-коды, ответы на секретные вопросы. Данный фактор наиболее распространён, однако уязвим к атакам перебора, социальной инженерии и утечкам баз данных.')

add_para('2) Фактор владения (что-то, что пользователь имеет): аппаратные токены (YubiKey), смарт-карты, мобильные устройства с одноразовыми кодами (TOTP). Обеспечивает более высокий уровень защиты, но связан с затратами на оборудование и риском потери носителя.')

add_para('3) Фактор неотъемлемости (что-то, что является частью пользователя): биометрические характеристики — отпечатки пальцев, рисунок радужной оболочки глаза, геометрия лица, голос, рисунок вен ладони. Биометрические данные невозможно забыть или потерять, что делает их наиболее надёжным фактором аутентификации.')

add_para('Парольная аутентификация, несмотря на повсеместное распространение, обладает рядом существенных недостатков. По данным исследования NordPass за 2024 год, наиболее часто используемые пароли включают простые комбинации вида «123456», «password», «qwerty». Более 60% пользователей повторно используют одни и те же пароли для различных сервисов, создавая каскадный эффект при компрометации одного из них.')

add_para('Многофакторная аутентификация (Multi-Factor Authentication, MFA) позволяет значительно повысить уровень безопасности за счёт комбинации двух и более факторов. По данным Microsoft Security Research, использование MFA предотвращает 99,9% автоматизированных атак на учётные записи. Тем не менее классические реализации MFA (SMS-коды, push-уведомления, приложения-аутентификаторы) требуют дополнительных действий от пользователя, что снижает удобство и скорость входа в систему.')

add_para('Биометрическая аутентификация представляет собой оптимальное решение, сочетающее высокий уровень безопасности с минимальным вовлечением пользователя. Среди методов биометрической аутентификации распознавание лиц выделяется рядом преимуществ:')

add_para('— бесконтактность: не требуется физический контакт с устройством, что важно с точки зрения гигиены и удобства;')
add_para('— возможность использования стандартного оборудования: достаточно обычной веб-камеры, встроенной в ноутбук или монитор;')
add_para('— высокая скорость распознавания: современные нейросетевые модели выполняют распознавание за доли секунды;')
add_para('— возможность реализации в веб-приложениях: технологии WebRTC и WebGL позволяют выполнять биометрическую обработку непосредственно в браузере;')
add_para('— неинвазивность: процесс распознавания не вызывает дискомфорта у пользователя.')

add_para('Однако аутентификация по лицу имеет и ограничения. Основной угрозой является атака подделки (presentation attack или spoofing), при которой злоумышленник предъявляет фотографию или видеозапись лица легитимного пользователя. Для противодействия данной угрозе применяются механизмы проверки «живости» (liveness detection), требующие от пользователя выполнения определённых действий — моргания, поворота головы, демонстрации жестов.')

add_para('В контексте строительной отрасли основные угрозы информационной безопасности включают:')
add_para('— утечку проектной документации и коммерческой тайны при участии в тендерах;')
add_para('— несанкционированный доступ к финансовым данным, сметам и актам выполненных работ;')
add_para('— подделку документов и фальсификацию отчётности при строительном контроле;')
add_para('— нарушение конфиденциальности персональных данных сотрудников и субподрядчиков;')
add_para('— несанкционированное изменение прав доступа для получения возможности редактирования документов.')

add_para('Таким образом, разработка системы аутентификации на основе распознавания лиц с ролевой моделью управления доступом и механизмом проверки «живости» представляется актуальной задачей для повышения информационной безопасности корпоративных систем строительных организаций.')

# ---- 1.2 ----
add_heading_l('1.2 Обзор алгоритмов распознавания лиц и систем управления доступом')

add_para('Задача распознавания лиц в компьютерном зрении решается поэтапно и включает следующие стадии:')
add_para('1) Детекция лица — определение наличия и положения лица (лиц) на изображении или видеокадре. Результатом является ограничивающий прямоугольник (bounding box) для каждого обнаруженного лица.')
add_para('2) Выравнивание (alignment) — нормализация изображения лица с использованием ключевых точек (landmarks) для компенсации поворотов и наклонов головы.')
add_para('3) Извлечение признаков (feature extraction) — вычисление числового вектора (эмбеддинга, дескриптора), однозначно характеризующего лицо. Вектор генерируется нейронной сетью.')
add_para('4) Сравнение (matching) — определение расстояния между дескрипторами для верификации (сравнение «один к одному») или идентификации (сравнение «один ко многим»).')

add_para('Эволюция алгоритмов распознавания лиц прошла путь от классических методов (метод Виолы-Джонса, Local Binary Patterns, Eigenfaces) к глубоким нейронным сетям. Рассмотрим ключевые архитектуры.')

add_para('DeepFace (Facebook AI Research, 2014) — одна из первых глубоких свёрточных нейронных сетей для распознавания лиц. Архитектура включает 9 слоёв с более чем 120 миллионами параметров. Обучена на датасете Social Face Classification из 4,4 миллиона изображений 4030 человек. Достигла точности 97,35% на эталонном датасете Labeled Faces in the Wild (LFW), что впервые сравнялось с уровнем человеческого распознавания (97,5%).')

add_para('FaceNet (Google, 2015) — архитектура, обучающаяся с помощью функции потерь Triplet Loss. Для обучения формируются тройки изображений: якорное (anchor), позитивное (то же лицо) и негативное (другое лицо). Функция потерь минимизирует расстояние между якорем и позитивным примером и максимизирует расстояние между якорем и негативным:')
add_para('L = max(||f(a) - f(p)||² - ||f(a) - f(n)||² + α, 0)')
add_para('где α — маржа (margin), обычно равная 0,2. FaceNet генерирует 128-мерный вектор-эмбеддинг и достигает точности 99,63% на LFW. Данная архитектура лежит в основе библиотеки face-api.js, используемой в настоящей работе.')

add_para('ArcFace (Deng et al., 2018) — метод обучения, использующий аддитивную угловую маржу (Additive Angular Margin Loss) для повышения дискриминативности эмбеддингов:')
add_para('L = -log(exp(s·cos(θ_yi + m)) / (exp(s·cos(θ_yi + m)) + Σ exp(s·cos(θ_j))))')
add_para('где s — масштабный коэффициент, m — аддитивная угловая маржа, θ — угол между вектором признаков и весовым вектором класса. ArcFace достигает точности 99,83% на LFW и является одним из лучших открытых решений.')

add_para('ResNet (He et al., 2016) — архитектура глубоких остаточных сетей (Residual Networks), решающая проблему деградации при увеличении глубины сети. Ключевая идея — использование остаточных соединений (skip connections), позволяющих градиенту проходить через слои без затухания. Варианты ResNet-34 и ResNet-50 широко используются в качестве backbone-сетей для извлечения признаков лица. Модель FaceRecognitionNet в face-api.js основана на ResNet-34.')

add_para('Для детекции лиц в реальном времени в данной работе используется модель TinyFaceDetector — компактный одношаговый детектор, основанный на модифицированной архитектуре Tiny YOLO. Размер модели составляет 190 КБ (в формате TensorFlow.js), что позволяет загружать её в браузер с минимальной задержкой. Модель обеспечивает детекцию лиц за 20–30 мс на современных устройствах при разрешении входного изображения 640×480 пикселей.')

add_para('Для определения ключевых точек лица используется модель FaceLandmark68Net, определяющая 68 точек: контуры лица (17 точек), брови (по 5 точек), нос (9 точек), глаза (по 6 точек), рот (20 точек). Эти точки используются для выравнивания лица перед вычислением дескриптора, что повышает инвариантность к позе и мимике.')

add_para('Системы управления доступом (Access Control Systems) определяют, какие ресурсы и операции доступны пользователю после прохождения аутентификации. В теории информационной безопасности выделяют несколько моделей управления доступом.')

add_para('DAC (Discretionary Access Control) — дискреционная (избирательная) модель, в которой владелец ресурса самостоятельно определяет права доступа других пользователей. Модель реализована в большинстве файловых систем (UNIX-permissions). Преимущества: гибкость и простота. Недостатки: сложность администрирования при большом числе пользователей, отсутствие централизованного контроля.')

add_para('MAC (Mandatory Access Control) — мандатная модель, в которой решения о доступе принимаются на основе уровней секретности (грифов) субъектов и объектов. Модель используется в государственных и военных информационных системах (SELinux, МСВС). Преимущества: высокий уровень безопасности. Недостатки: жёсткость, высокие накладные расходы на администрирование.')

add_para('RBAC (Role-Based Access Control) — ролевая модель, формализованная в стандарте NIST INCITS 359-2004. Права доступа определяются не индивидуально для каждого пользователя, а через роли, соответствующие должностным обязанностям. Модель RBAC включает четыре компонента: пользователи (Users), роли (Roles), разрешения (Permissions) и сессии (Sessions). Преимущества: соответствие организационной структуре предприятия, простота администрирования, поддержка принципа минимальных привилегий (Principle of Least Privilege). RBAC является наиболее подходящей моделью для корпоративных систем.')

add_para('ABAC (Attribute-Based Access Control) — атрибутная модель, в которой решение о доступе принимается на основе атрибутов субъекта, объекта, среды и действия. Модель является наиболее гибкой, но и наиболее сложной в реализации.')

add_para('В разрабатываемой системе «СтройКонтроль» применяется модель RBAC с шестью ролями, соответствующими типичной организационной структуре строительного предприятия:')
add_para('— Администратор (admin) — полный доступ ко всем функциям, включая управление пользователями, ролями, назначениями на проекты и просмотр журнала аудита;')
add_para('— Директор (director) — создание и редактирование проектов, смет, документов;')
add_para('— Бухгалтер (accountant) — просмотр проектов, смет и документов;')
add_para('— Менеджер (manager) — создание и редактирование проектов, смет, документов;')
add_para('— Инженер (engineer) — просмотр проектов и документов;')
add_para('— Зритель (viewer) — только просмотр информации.')

add_para('Дополнительно реализован механизм назначения пользователей на проекты (Project Assignment), обеспечивающий гранулярный контроль: пользователь видит только те проекты, на которые он назначен администратором. Администратор имеет доступ ко всем проектам без ограничений.')

# ---- 1.3 ----
add_heading_l('1.3 Анализ существующих решений биометрической аутентификации и нормативно-правовой базы')

add_para('На рынке представлен ряд решений для биометрической аутентификации по лицу. Рассмотрим основные из них и проведём сравнительный анализ.')

add_para('Windows Hello (Microsoft) — встроенная система биометрической аутентификации операционной системы Windows 10/11. Использует инфракрасную камеру для построения карты глубины лица, что обеспечивает защиту от атак с использованием фотографий. Вероятность ложного допуска (FAR) — менее 1:100 000. Ограничения: привязка к экосистеме Windows, необходимость специализированной IR-камеры (Intel RealSense или аналогичной), невозможность использования в веб-приложениях.')

add_para('Apple Face ID — система распознавания лиц, используемая в устройствах iPhone и iPad (начиная с iPhone X, 2017). Применяет проектор структурированного инфракрасного излучения (dot projector), излучающий более 30 000 точек на лицо пользователя. Результат — 3D-карта лица с математической моделью. FAR — менее 1:1 000 000. Ограничения: доступна исключительно на устройствах Apple, проприетарная технология.')

add_para('Amazon Rekognition — облачный сервис компьютерного зрения, входящий в Amazon Web Services (AWS). Предоставляет API для детекции и распознавания лиц, анализа эмоций, определения возраста и пола. Точность распознавания — более 99% на эталонных датасетах. Ограничения: облачная модель предполагает передачу биометрических данных на серверы Amazon, что создаёт риски с точки зрения конфиденциальности и соответствия российскому законодательству (ФЗ-152); стоимость — $1 за 1000 запросов API.')

add_para('RecFaces (Россия) — российское решение для распознавания лиц, ориентированное на корпоративный сектор и системы контроля и управления доступом (СКУД). Обеспечивает интеграцию с камерами видеонаблюдения, турникетами, системами учёта рабочего времени. Ограничения: проприетарное ПО, высокая стоимость (от 500 000 руб./год), необходимость выделенного сервера.')

add_para('VisionLabs LUNA (Россия) — платформа распознавания лиц, используемая в банковском секторе и транспортной инфраструктуре. Обеспечивает точность более 99,5% и скорость обработки до 10 000 лиц в секунду. Ограничения: ориентирована на крупные предприятия, высокая стоимость внедрения.')

add_para('Сравнительный анализ существующих решений и разрабатываемой системы «СтройКонтроль» позволяет выявить следующие отличия:')

add_para('1) Обработка данных: существующие облачные решения (Amazon Rekognition) передают биометрические данные на внешние серверы, в то время как разрабатываемая система выполняет все биометрические вычисления в браузере пользователя, не передавая изображения лица на сервер. На сервер передаётся только числовой дескриптор (128 чисел).')

add_para('2) Стоимость: коммерческие решения (RecFaces, VisionLabs) требуют значительных лицензионных отчислений. Разрабатываемая система использует исключительно открытое ПО (Go, PostgreSQL, face-api.js, MediaPipe), что обеспечивает нулевую стоимость лицензий.')

add_para('3) Специализация: существующие решения являются универсальными. Разрабатываемая система специализирована для строительной отрасли и включает ролевую модель, отражающую организационную структуру строительного предприятия (директор, бухгалтер, менеджер, инженер).')

add_para('4) Liveness detection: Windows Hello и Face ID используют аппаратные средства (IR-камера, dot projector). Разрабатываемая система реализует программный liveness detection на основе распознавания жестов с помощью MediaPipe HandLandmarker, что не требует специализированного оборудования.')

add_para('5) Интеграция с корпоративной системой: разрабатываемый модуль тесно интегрирован с системой управления строительными проектами, обеспечивая не только аутентификацию, но и ролевой контроль доступа к конкретным проектам, сметам и документам.')

add_para('Нормативно-правовая база обработки биометрических данных в Российской Федерации включает следующие основные документы:')

add_para('Федеральный закон от 27.07.2006 №152-ФЗ «О персональных данных» — устанавливает требования к обработке персональных данных, включая биометрические. Согласно ст. 11, обработка биометрических персональных данных может осуществляться только при наличии письменного согласия субъекта. В контексте корпоративной системы это означает необходимость получения согласия сотрудника на обработку его биометрических данных при регистрации в системе.')

add_para('Федеральный закон от 27.07.2006 №149-ФЗ «Об информации, информационных технологиях и о защите информации» — определяет основы правового регулирования отношений в сфере информации и информационных технологий. Устанавливает требования к защите информации ограниченного доступа.')

add_para('ГОСТ Р ИСО/МЭК 19795-1-2007 «Информационные технологии. Биометрия. Эксплуатационные испытания и протоколы испытаний в биометрии» — определяет методологию тестирования биометрических систем, включая метрики FAR, FRR, EER.')

add_para('ГОСТ Р 54412-2011 «Информационные технологии. Биометрия. Обеспечение и оценка производительности биометрических систем» — устанавливает требования к оценке эффективности биометрических систем.')

add_para('Федеральный закон от 29.12.2022 №572-ФЗ «Об осуществлении идентификации и (или) аутентификации физических лиц с использованием биометрических персональных данных» — регулирует использование Единой биометрической системы (ЕБС) и устанавливает требования к операторам биометрических данных.')

add_para('Разрабатываемая система учитывает требования указанных нормативных актов: биометрические дескрипторы (числовые векторы) хранятся локально в базе данных организации, а не в облачных сервисах; обработка изображений лица производится на стороне клиента (в браузере) без передачи на сервер; ведётся журнал аудита всех действий с персональными данными; система может быть развёрнута на оборудовании организации без подключения к внешним сервисам.')

add_para('Выводы по главе 1. Проведённый аналитический обзор показал, что биометрическая аутентификация по лицу является перспективным методом защиты корпоративных информационных систем. Существующие коммерческие решения обладают высокой стоимостью и не учитывают специфику строительной отрасли. Модель RBAC наиболее подходит для ролевого управления доступом в строительных организациях. Разрабатываемая система сочетает открытые технологии, обработку биометрии на стороне клиента и специализированную ролевую модель, что выгодно отличает её от существующих аналогов.')

